$_MODULE['<{prestablog}prestashop>ai_fc42865ab309f2e642480630b92db575'] = 'Dieses Feld darf nicht leer sein.';
$_MODULE['<{prestablog}prestashop>ai_3fb66787028092600f08cd2c37cc1027'] = 'Ich verwalte eine Website mit dem Thema %theme%. Können Sie einige Blog-Themen vorschlagen, die ich entwickeln sollte? Formatieren Sie die Antwort als HTML-Tabelle mit zwei Spalten: eine für das \'Thema\' und eine für den \'Beliebtheitsscore\' (eine Zahl zwischen 1 und 100). Jedes Thema sollte in einer separaten Zeile stehen.';
$_MODULE['<{prestablog}prestashop>ai_3c299be1cf8d8948c25b1433eecc542f'] = 'Verwenden Sie das Thema "%theme%". Erstellen Sie eine Tabelle mit Titel- und Schlüsselwortvariationen, die Long-Tail-Begriffe gruppieren, die in Suchmaschinen ranken können. Formatieren Sie die Antwort als HTML-Tabelle mit zwei Spalten: eine für die Titel und eine für die Schlüsselwörter.';
$_MODULE['<{prestablog}prestashop>ai_1065948d549c2bc51ea828181f2328cf'] = 'Ich möchte, dass Sie einen SEO-optimierten Blog-Artikel zum Thema "%theme%" mit einem Schreibstil von "%style%" verfassen. Strukturieren Sie den Text in HTML mit den entsprechenden Tags. Der Artikel sollte ansprechend, relevant, hochwertig und als von KI erstellter Inhalt nicht erkennbar sein. Beginnen Sie mit einem einleitenden Absatz, ohne den Blog zu erwähnen oder eine Überschrift zu verwenden. Verwenden Sie Unterüberschriften, die mit h2- und h3-Tags formatiert sind und Long-Tail-Titel zur Verbesserung des SEO enthalten. Integrieren Sie Long-Tail-Schlüsselwörter natürlich und heben Sie sie mit strong-Tags hervor. Stellen Sie sicher, dass jeder Abschnitt mindestens 100 Wörter enthält, mit fließenden Übergängen. Schließen Sie mit einer Zusammenfassung ab, die die wichtigsten Punkte verstärkt, ohne neue Informationen hinzuzufügen.';
$_MODULE['<{prestablog}prestashop>ai_bdfb00881e5b80ef206858f72db30420'] = 'Erstellen Sie eine fesselnde Einleitung, die in der Blog-Kategorie angezeigt wird, um den Artikel "%theme%" vorzustellen. Diese Einleitung sollte kurz, ansprechend und eine allgemeine Übersicht über den Inhalt des Artikels geben.';
$_MODULE['<{prestablog}prestashop>ai_dceabd505243b76be8191a63ff37046c'] = 'Erstellen Sie auf der Grundlage des Themas "%theme%" einen überzeugenden Titel, der die Aufmerksamkeit auf sich zieht und den Inhalt effektiv zusammenfasst. Und fügen Sie keine Anführungszeichen um Ihre Antwort hinzu.';
$_MODULE['<{prestablog}prestashop>ai_23e8bc5c05172b396e2a5bad9b1d6e7f'] = 'Erstellen Sie auf der Grundlage des Themas "%theme%" einen kurzen und effektiven Meta-Titel, der SEO-freundlich ist und den Inhalt genau darstellt. Und fügen Sie keine Anführungszeichen um Ihre Antwort hinzu.';
$_MODULE['<{prestablog}prestashop>ai_cb71ee03fd4e763b82325c5fa0c28711'] = 'Erstellen Sie auf der Grundlage des Themas "%theme%" eine prägnante und überzeugende Meta-Beschreibung, die zum Klicken anregt und für Suchmaschinen optimiert ist. Und fügen Sie keine Anführungszeichen um Ihre Antwort hinzu.';
